function ReporteEnInformatica($id){
    require("config.php");
    //CUANDO LO PONGO EN 2 SIGNIFICA QUE HA SIDO ELIMINADA.
    $EnReporte = 0;
    $En_reportesConsulta = 0 ;
    $sql = "select 
    reportesconsultas.idConsulta as QidConsulta,
    reportesconsultas.estado as EstadoConsulta,
    (select reportes.id_rep from reportes where reportes.id_rep_consulta = QidConsulta) as IdReporte,
    (select reportes.estado from reportes where reportes.id_rep_consulta = QidConsulta) as ReporteEstado
    
    
    from
    reportesconsultas
    
    where
    reportesconsultas.idConsulta = '".$id."'";
    // echo $sql;
    $rc= $conexion -> query($sql);
    if ($conexion->query($sql) == TRUE){   
        if($f = $rc -> fetch_array())
            {
                if ($f['EstadoConsulta']==1 AND $f['ReporteEstado']==0 ){
                    //ES de informatica
                    return "INFORMATICA";

                } 
                
                if ($f['EstadoConsulta']==1 AND $f['ReporteEstado']==1 ){
                    //ES de informatica
                    return "INFORMATICA-JEFE";

                } 
                
                if ($f['EstadoConsulta']==1 AND $f['ReporteEstado']==2 ){
                    //ES de informatica
                    return "AUTORIZA";

                } 

                if ($f['EstadoConsulta']==1 AND $f['ReporteEstado']==3 ){
                    //ES de informatica
                    return "PRE-PUBLICAR";

                } 
            }
        else
            {return FALSE;}
    } else {return FALSE;}





    
}



