function camposDescripcion($id,$f){
    require("config.php");
    $sql = "SELECT * FROM reportes WHERE id_rep_consulta='".$id."'";
    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array()){
        $sql = $f['sql1'];
        $sql2 =$f['sql2'];
        $sql3 = $f['sql3'];
        $descripcion = $f['descripcion'];
    }else{
        return FALSE;
    }
    if(!empty($sql) == true){
        $tabla_titulos = "";
        $r1 = $conexion -> query($sql);
        if($r1){
            while($finfo = $r1->fetch_field()){//OBTENER LAS COLUMNAS
                $tabla_titulos=$tabla_titulos.', '.$finfo->name;
            }
        }
    }
    if(!empty($sql2) == true){
        $r2 = $conexion -> query($sql2);
        if($r2){
            while($finfo = $r2->fetch_field()){//OBTENER LAS COLUMNAS
                $tabla_titulos=$tabla_titulos.', '.$finfo->name;
            }
        }
    }
    if(!empty($sql3) == true){
        $r3 = $conexion -> query($sql3);
        if($r3){
            while($finfo = $r3->fetch_field()){//OBTENER LAS COLUMNAS
                $tabla_titulos=$tabla_titulos.', '.$finfo->name;
            }
        }
    }
    $tabla_titulos= trim($tabla_titulos, ', '); //quita la ultima coma
    /*if($f==1){
        $tabla_titulos="".$descripcion." Nombre de las columnas del reporte: ".$tabla_titulos."";
    }else{
        $find = '.';
        $pos = strpos($descripcion, $find);
        $resultado = substr($descripcion, 0, $pos);
        $tabla_titulos="".$resultado.". Nombre de las columnas del reporte: ".$tabla_titulos."";
    }*/
    return $tabla_titulos;
}

