function numeroOficioPublico($consulta){
require("config.php");
$sql = "SELECT * FROM contadores WHERE id='0'";
$rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array()){
        if ($consulta==TRUE) {
            return $f['NumOficioPublico'];
        }else{ // sino es consulta entonces aumentarle y aumentar el contador de ceropapel
    // la diferencia entre ceropapel y este, es que cero papel se multiplica
    // por las copias que se entregan o con copia, para estadistica de cuanto se ha ahorrado
            $n2 = $f['NumOficioPublico'] + 1;
            //$n2 = $f['npase_idenficador'].$n2;
            $sql="UPDATE contadores SET NumOficioPublico='".$n2."' WHERE id='0'";
            $resultado = $conexion -> query($sql);
            if ($conexion->query($sql) == TRUE) {
                return $n2;
            }else{
                return  FALSE;
            }
        }
    }else{ 
        return FALSE;
    }
}
