function DiasFaltantes($Div, $Valor){


	echo '
	<div id="'.$Div.'" class="GraficaPorcentaje" >
		<canvas id="'.$Div.'canvas" class="GraficaPorcentajeCanvas"></canvas>    
		<div  id="'.$Div.'CanvasGLabel"  class="GraficaPorcentajeLabel" style="color: #dc2d2d;">0</div>
		<div  id="CanvasGLabelSigno"  class="GraficaPorcentajeSigno" style="font-size:7pt; color: #dc2d2d;"><br>Días<br>faltantes</div>
	</div>
	';
	
	echo "
	<script>
	function GraficaPorcentaje".$Div."(){
		var opts = {
			lines: 12, 
			angle: 0.22,
			lineWidth: 0.1, 
			pointer: {
				length: 0.5, strokeWidth: 0.035, color: '#000000' 
			},
			limitMax: 'false', 
			colorStart: '#1d4d9f', 
			colorStop: '#dc2d2d',
			strokeColor: '#1d4d9f', 
			generateGradient: true
		};
		var target = document.getElementById('".$Div."canvas'); 
		var gauge = new Donut(target).setOptions(opts);
		gauge.maxValue = 100; 
		gauge.animationSpeed = 20; 
		gauge.set(".$Valor."); 
		gauge.setTextField(document.getElementById('".$Div."CanvasGLabel'));
		
		textRenderer.render = function(gauge){
			//percentage = gauge.displayedValue / gauge.maxValue
			//this.el.innerHTML = (percentage * 100).toFixed(2) + '%'
			this.el.innerHTML = gauge.displayedValue + 'días faltantes'
	
		};
		
	
	}  
	GraficaPorcentaje".$Div."();
	</script>
	
	";
	

}

