function casoCompartidoCon($id){
    static $cache = array();
    if (array_key_exists($id, $cache)) {
        return $cache[$id];
    }

    global $conexion;
    if (!isset($conexion)) {
        require("config.php");
    }

    $num = "";
    $sql = "SELECT nitavu FROM cp_colaboradores WHERE numcaso=".$id." and activo=0";
    $r = $conexion->query($sql);
    if ($r && $r->num_rows > 0) {
        while($f = $r->fetch_array()){
            $num = $num.$f['nitavu'].'/';
        }
        $num = trim($num, '/');
        $num1 = explode('/',$num);
        $cache[$id] = $num1;
        return $num1;
    }

    $cache[$id] = 0;
    return 0;
    
}

function subioArchivos($numcaso,$nitavu){
    static $cache = array();
    $key = $numcaso."|".$nitavu;
    if (array_key_exists($key, $cache)) {
        return $cache[$key];
    }

    global $conexion;
    if (!isset($conexion)) {
        require("config.php");
    }

    $sql = "SELECT * FROM cp_historialdocumentos WHERE NumCaso=".$numcaso." and nitavuSube=".$nitavu."";
    $rc= $conexion->query($sql);
    if($rc && ($f = $rc->fetch_array())){
        $cache[$key] = 'TRUE';
        return 'TRUE';
    }

    $cache[$key] = 'FALSE';
    return 'FALSE';
}

