function MiToken_generate(){
    $len = 16;
    $cadena_base =  'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
    $cadena_base .= '0123456789' ;
    // $cadena_base .= '!@#%^&*()_,./<>?;:[]{}\|=+';
   
    $password = '';
    $limite = strlen($cadena_base) - 1;
   
    for ($i=0; $i < $len; $i++)
      $password .= $cadena_base[rand(0, $limite)];
   
    return $password;
}
