 function count_dimension($array) {
 $longitud = count($array);
 $mayor=0;
 //Recorro todos los elementos
 for($i=0; $i<$longitud; $i++)
       {
         
       //saco el valor de cada elemento 
       //y busco de todos los elementos el de mayor dimension
       if(is_array($array)){     
         if(count($array[$i]) > $mayor) {
             $mayor = count($array[$i]);
         }
         
       }
      
     
     }


return $mayor;
    }
