function Vocal($Letra){
    if($Letra == "A" || $Letra == "E" || $Letra == "I" || $Letra == "O" || $Letra == "U"){
        return True;
    }else{
        return False;
    }
}


function Proposicion($p){
    if($p =="DA" || $p== "DAS" || $p== "DE" || $p== "DEL" || $p== "DER" || $p== "DI" || $p=="DIE" ||
       $p=="DD" || $p=="EL" || $p=="LA" || $p=="LOS" || $p=="LAS" || $p=="LE" ||  $p=="LES" || $p=="MAC" ||
       $p=="MC" || $p=="VAN" || $p=="VON" || $p=="Y"){
        return True;
    }else{
        return False;
    }
}

