function  TramiteAnteriorTieneAhorroPrevio($CURP, $IdPrograma){
    require("config.php");
    $sql = "select IdPrograma, Programa, NombreTramite,IdTipoTramite as TipoTramiteId,
    (SELECT IdTramite from tramites WHERE Curp = '".$CURP."' AND IdTipoTramite = TipoTramiteId) as FolioTramite,
    (SELECT AhorroPrevio FROM tramites WHERE Curp = '".$CURP."' AND IdTramite = FolioTramite) as Ahorro
    from tramitestipo 
    WHERE IdPrograma='".$IdPrograma."' order by Dependencia ASC LIMIT 1";
    echo $sql;
    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array())
    {				
         return $f['Ahorro'];
    }else{
        return FALSE;
    }
}

