function NombrePrograma($idPrograma){
    require("config.php");
    $sql = "Select Programa from programa where IdPrograma = ".$idPrograma."";
    
    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array())
    {				
        return $f['Programa'];
    }else{
        return FALSE;
    }
}

function DescripcionPrograma($idPrograma){
    require("config.php");
    $sql = "Select Descripcion from cat_programa where IdPrograma = ".$idPrograma."";

    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array())
    {				
        return $f['Descripcion'];
    }else{
        return FALSE;
    }
}

