function issetSolicitudDato($FolioTramite, $IdRequisito, $IdCategoria, $tipoInfo){	
	require("config.php");
		$sql = "select count(*) as Valor from solicitudesinformacion where IdSolicitud='".$FolioTramite."' AND IdRequisito='".$IdRequisito."' and Clase=".$IdCategoria." and IdTipoInformacion = ".$tipoInfo."";	
		//echo $sql; 
		$rc= $conexion -> query($sql);
		if($f = $rc -> fetch_array())
			{				
				return $f['Valor'];
			}
		 else {return FALSE;}
}

function GuardarSolicitudDato($FolioTramite, $IdRequisito, $Dato, $TipoRequisito, $NitavuCaptura, $IdCategoria, $tipoInfo){	
	require("config.php");
	 //Para Guardar los Datos Iniciales
	 if (issetSolicitudDato($FolioTramite, $IdRequisito, $IdCategoria, $tipoInfo) == 0) {//identificamos si ya teiene dato
		//un insert
		return SolicitudDatoInsert($FolioTramite, $IdRequisito, $Dato, $TipoRequisito, $NitavuCaptura, $IdCategoria,$tipoInfo);
	 } else {
		 //un update
		 return SolicitudDatoUpdate($FolioTramite, $IdRequisito, $Dato, $NitavuCaptura, $IdCategoria,$tipoInfo);
	 }
}

function SolicitudDatoInsert($FolioTramite, $IdRequisito, $Dato, $TipoRequisito, $NitavuCaptura, $IdCategoria,$tipoInfo){
	require("config.php");

	if($IdRequisito == 0){
		if( validarCurpUtilizadoSolicitudes($FolioTramite,$Dato)<>0){
			echo "<script>$.toast({
				heading: 'Warning',
				text: 'Error:  Error al Guardar el Curp ".$Dato.",No pudes duplicar un CURP en un mismo trámite!;)',
				showHideTransition: 'plain',
				icon: 'warning'
			});</script>";
        }else{
			$sql = "INSERT INTO solicitudesinformacion(IdSolicitud, IdRequisito, Dato, NitavuCaptura, Fecha, Hora, Clase, IdTipoInformacion) 
			VALUES('".$FolioTramite."', '".$IdRequisito."', '".$Dato."', '".$NitavuCaptura."','".$fecha."', '".$hora."', ".$IdCategoria.", ".$tipoInfo.")";	
			//echo $sql;
			if ($conexion->query($sql) == TRUE){
				historia($NitavuCaptura,"solicitudes: Guardo en la solicitud con Folio " . $FolioTramite." el Requisito con Id ".$IdRequisito.", Dato: ".$Dato." de la Clase ".$IdCategoria."");
				return TRUE;	
			}
			else {
				return FALSE;
			}
		
		}
	}else{
		$sql = "INSERT INTO solicitudesinformacion(IdSolicitud, IdRequisito, Dato, NitavuCaptura, Fecha, Hora, Clase, IdTipoInformacion) 
			VALUES('".$FolioTramite."', '".$IdRequisito."', '".$Dato."', '".$NitavuCaptura."','".$fecha."', '".$hora."', ".$IdCategoria.",".$tipoInfo.")";	
		//echo $sql; 
					
		if ($conexion->query($sql) == TRUE){
			historia($NitavuCaptura,"solicitudes: Guardo en la solicitud con Folio " . $FolioTramite." el Requisito con Id ".$IdRequisito.", Dato: ".$Dato." de la Clase ".$IdCategoria."");
			return TRUE;	
		}
		else {
			return FALSE;
		}
	}
}

