function buscarDependientesAnteriores($FolioTramite){
    require("config.php");
    $sql = "SELECT DISTINCT Max(Clase) as Valor from solicitudesinformacion where IdSolicitud=".$FolioTramite." and Clase In( 30,39,40,41,42,43,44,45,46,47)";
    // echo $sql;
    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array())
    {		
        if($f['Valor']==30){
            return 39;
        }else if($f['Valor']==47){
            return FALSE;
        }else{
            return $f['Valor']+1;
        }      
        
    }
     else {return FALSE;}
}

function buscarApoyosAnteriores($FolioTramite){
    require("config.php");
    $sql = "SELECT DISTINCT Max(Clase) as Valor from solicitudesinformacion where IdSolicitud=".$FolioTramite." and Clase In( 34,49,50,51,52,53,54,55,56,57)";
    // echo $sql;
    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array())
    {		
        if($f['Valor']==34){
            return 49;
        }else if($f['Valor']==57){
            return FALSE;
        }else{
            return $f['Valor']+1;
        }      
        
    }
     else {return FALSE;}
}

