function encontrarDependenciadeRequisito($IdRequisito){
    require("config.php");
    $sql = "Select Depende from solicitudesrequisitos where IdRequisito = ".$IdRequisito."";

    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array())
    {				
        return $f['Depende'];
    }else{
        return FALSE;
    }
}


