function existenMasDependientes($FolioTramite){
    require("config.php");
    $categorias = '';
    $cat = "";
    $sql = "SELECT Clase from solicitudesinformacion WHERE IdSolicitud=".$FolioTramite." and Clase in (39,40,41,42,43,44,45,46,47) GROUP BY Clase";

    $r = $conexion -> query($sql); 

    $r_count = $r -> num_rows;
    if($r_count >0){
        while($f = $r -> fetch_array()){
            $categorias = $categorias.$f['Clase'].'/';
        }
        $categorias = trim( $categorias, '/');    
        $cat = explode('/',$categorias);
    }

    return $cat;
}

