function versionAsset($ruta, $type = 'text/javascript') {
    $tipo = substr(strtolower($ruta),-2);
    $version = @filemtime($ruta) ?: 0;
    $ruta = $ruta . '?' . $version;

    switch ($tipo) {
        case 'ss': $asset="<link rel='stylesheet' href='{$ruta}'>"; break;
        case 'js': $asset="<script type='{$type}' src='{$ruta}'></script>";break;
        default: $asset='';break;
    }
    return $asset;
    //echo (versionAsset('lib/google_charts_loader.js'));
}


function Procentajesolicitudestemp($FolioTramite){	
    require("config.php");
    $sql = "select * from estadocapturasolicitudes WHERE IdSolicitud = ".$FolioTramite;				
    //echo $sql;
    $vacios =0;
    $llenos = 0;
    $porcentaje=0;
    $msg = "";
    $rc= $conexion -> query($sql);
    if($f = $rc -> fetch_array()){				
        $total = $f['RequisitosRequeridos'];
        $llenos = $f['RequisitosRequeridosLlenos'];					
        $porcentaje=(($llenos*100)/$total);
            // return $porcentaje;
        return number_format($porcentaje,0);
    }else{
        return FALSE;
    }
    
}

function GraficaPorcentaje2($Div, $Valor){

    //echo $Valor;

	echo '
	<div id="'.$Div.'" class="GraficaPorcentaje" >
		<canvas id="'.$Div.'canvas" class="GraficaPorcentajeCanvas"></canvas>    
		<div  id="'.$Div.'CanvasGLabel"  class="GraficaPorcentajeLabel">'.$Valor.'</div>
		<div  id="CanvasGLabelSigno"  class="GraficaPorcentajeSigno">%</div>
	</div>
	';
	
	echo "
	<script>
	function GraficaPorcentaje".$Div."(){
		var opts = {
			lines: 12, 
			angle: 0.22,
			lineWidth: 0.1, 
			pointer: {
				length: 0.5, strokeWidth: 0.035, color: '#000000' 
			},
			limitMax: 'false', 
			colorStart: '#A1C30D', 
			colorStop: '#2DA3DC',
			strokeColor: '#A1C30D', 
			generateGradient: true
		};
		var target = document.getElementById('".$Div."canvas'); 
		var gauge = new Donut(target).setOptions(opts);
		gauge.maxValue = 100; 
		gauge.animationSpeed = 20; 
		gauge.set(".$Valor."); 
		gauge.setTextField(document.getElementById('".$Div."CanvasGLabel'));
		
		/*textRenderer.render = function(gauge){
			//percentage = gauge.displayedValue / gauge.maxValue
			//this.el.innerHTML = (percentage * 100).toFixed(2) + '%'
			this.el.innerHTML = gauge.displayedValue + '%'
	
		};*/
		
	
	}  
	GraficaPorcentaje".$Div."();
	</script>
	
	";
	

}

