function localidadViviendaConstruccion($IdDelegacion,$IdPrograma,$Folio){
    require("config.php");
    $IdCiudad = IdCiudadViviendaConstruccion($IdDelegacion,$IdPrograma,$Folio);
    $sql = 'SELECT IdLocalidad FROM datosvivienda WHERE IdDelegacion ="'.$IdDelegacion.'" and IdPrograma="'.$IdPrograma.'" and Folio="'.$Folio.'"';
    //echo $sql;
    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){	
        if($f['IdLocalidad']<>''){
            $sql1= 'SELECT Nombre_Localidad FROM localidad WHERE  IdMunicipio = '.$IdCiudad.' and IdLocalidad='.$f['IdLocalidad'].'';
            $rc1= $Vivienda -> query($sql1);
            if($f1 = $rc1 -> fetch_array()){	
                return $f1['Nombre_Localidad'];
            }else{
                return FALSE;
            }
        }else{
            return 'NO CAPTURADO';
        }			
            
    }else{
        return FALSE;
    }
}

function coloniaViviendaConstruccion($IdDelegacion,$IdPrograma,$Folio){
    require("config.php");
    $IdCiudad = IdCiudadViviendaConstruccion($IdDelegacion,$IdPrograma,$Folio);
    $sql = 'SELECT IdColonia FROM datosvivienda WHERE IdDelegacion ="'.$IdDelegacion.'" and IdPrograma="'.$IdPrograma.'" and Folio="'.$Folio.'"';
    //echo $sql;
    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){	
        if($f['IdColonia']<>''){
            $sql1= 'SELECT Colonia from catcolonia WHERE  IdMunicipio = '.$IdCiudad.' and IdColonia='.$f['IdColonia'].'';
            $rc1= $Vivienda -> query($sql1);
            if($f1 = $rc1 -> fetch_array()){	
                return $f1['Colonia'];
            }else{
                return FALSE;
            }
        }else{
            return 'NO CAPTURADO';
        }			
            
    }else{
        return FALSE;
    }
}

