function domicilioDondeReside($IdDelegacion,$IdPrograma,$Folio){
     //ESTE MUESTRA DATOS DE DOMICILIO DONDE RESIDE
     echo "<div>";
     echo '<table class="tarjeta" style="font-family:Verdana;">';
         echo "<tr style='background-color:#9C9FA0;'><td colspan='4'><span style='font-size:15px; color:#fff;'><center>DOMICILIO DONDE RESIDE</center></span></td></tr>";
         echo '<tr style="font-size:15px; color:#9C9FA0;">
                 <td style="width:25%;">Domicilio (Segun INE):</td> <td style="color:#3E9CD1; width:25%;">'.domicilioINEVivienda($IdDelegacion,$IdPrograma,$Folio).'</td><td style="width:25%;">Número Exterior:</td><td style="color:#3E9CD1; width:25%;">'.numeroExteriorVivienda($IdDelegacion,$IdPrograma,$Folio).'</td>
             </tr>
             <tr style="font-size:15px; color:#9C9FA0;">
                 <td style="width:25%;">Entre Calle:</td><td style="color:#3E9CD1; width:25%;">'.calle1Vivienda($IdDelegacion,$IdPrograma,$Folio).'</td><td style="width:25%;">Número Interior:</td><td style="color:#3E9CD1; width:25%;">'.numeroInteriorVivienda($IdDelegacion,$IdPrograma,$Folio).'</td>
             </tr>
             <tr style="font-size:15px; color:#9C9FA0;">
                 <td style="width:25%;">Y Calle:</td> <td style="color:#3E9CD1; width:25%;">'.calle2Vivienda($IdDelegacion,$IdPrograma,$Folio).'</td><td style="width:25%;"></td><td style="width:25%;"></td>
             </tr>
             <tr style="font-size:15px; color:#9C9FA0;">
                 <td style="width:25%;">Ciudad:</td><td style="color:#3E9CD1; width:25%;">'.ciudadVivienda($IdDelegacion,$IdPrograma,$Folio).'</td><td style="width:25%;"></td><td style="width:25%;"></td>
             </tr >
             <tr style="font-size:15px; color:#9C9FA0;">
                 <td style="width:25%;"> Localidad: </td> <td style="color:#3E9CD1; width:25%;">'.localidadVivienda($IdDelegacion,$IdPrograma,$Folio).'</td><td style="width:25%;"></td><td style="width:25%;"></td>
