        echo "<input type='hidden' name='nombeneficiario' id='nombeneficiario' value='".$Beneficiario."'>";
        if($NumContrato <> ''){
            echo "<br><span style='color:#9C9FA0;'> Núm. Contrato: </span> <span style='color:#E3D79F;'>".$NumContrato."</span>";
        }
        if($numEscritura <> ''){
