function calcularEgresoMensaul($FolioTramite){
    require("config.php");
    $sql = 'SELECT sum(Dato) as egresoMensual from solicitudesinformacion WHERE IdSolicitud = '.$FolioTramite.' and Clase = 10 and (IdRequisito = 78 or IdRequisito = 79 or IdRequisito = 80 or IdRequisito = 81 or IdRequisito = 82 or IdRequisito = 83 or IdRequisito = 84)';
    $rc= $conexion -> query($sql);
    while($f = $rc -> fetch_array()){
       return $f['egresoMensual'];
    }
}

function revisarSiYaSeCreoCorridaFinanciera($FolioTramite){
    require("config.php");
    $sql = 'SELECT count(*) as total from solicitudesinformacion where IdTipoInformacion = 2 and IdSolicitud = '.$FolioTramite.'';
    $r = $conexion -> query($sql);
    while($f = $r -> fetch_array()){
        return $f['total'];
    }
}

