function busquedaPorNombre($Nombres, $Apaterno, $Amaterno, $link){
    require("config.php");
    $consulta = "SELECT (CASE WHEN contratos.NumContrato IS NULL THEN 
    (CASE WHEN solicitudes.Cancelado = 0 THEN 'Solicitud vigente' ELSE 'Solicitud cancelada' END) 
    Else CONCAT('Contrato ', CONVERT(estatuscuentas.Descripcion,varchar(15)))
    END) AS EstatusCuenta, solicitudes.IdDelegacion, delegaciones.Delegacion,
    solicitudes.IdPrograma, programa.Programa, solicitudes.Folio, case when contratos.NumContrato is null then solicitudes.FechaCaptura else contratos.FechaEmision end As FechaCaptura, 
    solicitantes.Paterno, solicitantes.Materno, solicitantes.Nombre,
    solicitantes.FNacimiento, datosconyuge.Paterno AS Paterno_Conyuge, datosconyuge.Materno AS Materno_Conyuge, datosconyuge.Nombre AS Nombre_Conyuge,
    datosconyuge.FNacimiento AS FechaN_Conyuge, estatus.Estatus, solicitudes.Cancelado as Cancelado 
FROM estatuscuentas RIGHT OUTER JOIN
controlcontratos ON estatuscuentas.idEstatusCuenta = controlcontratos.EstatusCuenta RIGHT OUTER JOIN
    contratos ON controlcontratos.NumContrato = contratos.NumContrato RIGHT OUTER JOIN
    solicitudes ON contratos.IdDelegacion = solicitudes.IdDelegacion AND contratos.IdPrograma = solicitudes.IdPrograma AND
    contratos.Folio = solicitudes.Folio LEFT OUTER JOIN
    delegaciones ON solicitudes.IdDelegacion = delegaciones.IdDelegacion LEFT OUTER JOIN
    programa ON solicitudes.IdPrograma = programa.IdPrograma LEFT OUTER JOIN
    estatus RIGHT OUTER JOIN
    solestatus ON estatus.IdEstatus = solestatus.IdEstatus ON solicitudes.IdDelegacion = solestatus.IdDelegacion AND
    solicitudes.IdPrograma = solestatus.IdPrograma AND solicitudes.Folio = solestatus.Folio LEFT OUTER JOIN
    datosconyuge ON solicitudes.IdDelegacion = datosconyuge.IdDelegacion AND solicitudes.IdPrograma = datosconyuge.IdPrograma AND
    solicitudes.Folio = datosconyuge.Folio LEFT OUTER JOIN
    solicitantes ON solicitudes.IdSolicitante = solicitantes.IdSolicitante
WHERE   (1 = 1)";   
if(strlen($Apaterno) > 0){
    $consulta = $consulta."and CONCAT(solicitantes.Paterno,' ',solicitantes.Materno,+' ',solicitantes.Nombre) like '%".$Apaterno."%'";
}
if(strlen($Amaterno) > 0){
    $consulta = $consulta."and CONCAT(solicitantes.Paterno,' ',solicitantes.Materno,+' ',solicitantes.Nombre) like '%".$Amaterno."%'";
} 
if(strlen($Nombres) > 0){
    $consulta = $consulta."and CONCAT(solicitantes.Paterno,' ',solicitantes.Materno,+' ',solicitantes.Nombre) like '%".$Nombres."%'";
}
$consulta = $consulta."Union
SELECT (CASE WHEN contratos.NumContrato IS NULL THEN (CASE WHEN solicitudes.Cancelado = 0 THEN 'Solicitud vigente' ELSE 'Solicitud cancelada' END) Else CONCAT('Contrato ', CONVERT(estatuscuentas.Descripcion,varchar(15))) END) AS EstatusCuenta,  solicitudes.IdDelegacion, delegaciones.Delegacion,
    solicitudes.IdPrograma, programa.Programa, solicitudes.Folio, case when contratos.NumContrato is null then solicitudes.FechaCaptura else contratos.FechaEmision end As FechaCaptura, 
    solicitantes.Paterno, solicitantes.Materno, solicitantes.Nombre,
    solicitantes.FNacimiento, datosconyuge.Paterno AS Paterno_Conyuge, datosconyuge.Materno AS Materno_Conyuge, datosconyuge.Nombre AS Nombre_Conyuge,
    datosconyuge.FNacimiento AS FechaN_Conyuge, estatus.Estatus, solicitudes.Cancelado as Cancelado 
FROM         estatuscuentas RIGHT OUTER JOIN
    controlcontratos ON estatuscuentas.idEstatusCuenta = controlcontratos.estatuscuenta RIGHT OUTER JOIN
    contratos ON controlcontratos.NumContrato = contratos.NumContrato RIGHT OUTER JOIN
    solicitudes ON contratos.IdDelegacion = solicitudes.IdDelegacion AND contratos.IdPrograma = solicitudes.IdPrograma AND
    contratos.Folio = solicitudes.Folio LEFT OUTER JOIN
    delegaciones ON solicitudes.IdDelegacion = delegaciones.IdDelegacion LEFT OUTER JOIN
    programa ON solicitudes.IdPrograma = programa.IdPrograma LEFT OUTER JOIN
    estatus RIGHT OUTER JOIN
    solestatus ON estatus.IdEstatus = solestatus.IdEstatus ON solicitudes.IdDelegacion = solestatus.IdDelegacion AND
    solicitudes.IdPrograma = solestatus.IdPrograma AND solicitudes.Folio = solestatus.Folio LEFT OUTER JOIN
    datosconyuge ON solicitudes.IdDelegacion = datosconyuge.IdDelegacion AND solicitudes.IdPrograma = datosconyuge.IdPrograma AND
    solicitudes.Folio = datosconyuge.Folio LEFT OUTER JOIN
    solicitantes ON solicitudes.IdSolicitante = solicitantes.IdSolicitante
Where 1 = 1";
if(strlen($Apaterno) > 0){
    $consulta = $consulta." and CONCAT(datosconyuge.Paterno,' ',datosconyuge.Materno,' ',datosconyuge.Nombre) like '%".$Apaterno. "%'";
}
if(strlen($Amaterno) > 0){
    $consulta = $consulta." and CONCAT(datosconyuge.Paterno,' ',datosconyuge.Materno,' ',datosconyuge.Nombre) like '%".$Amaterno."%'";
}   
if(strlen($Nombres) > 0){
    $consulta = $consulta."  and CONCAT(datosconyuge.Paterno,' ',datosconyuge.Materno,' ',datosconyuge.Nombre) like '%".$Nombres."%'";
}
$consulta = $consulta." Order by FechaCaptura Desc";

//echo $consulta;
$r1 = $Vivienda -> query($consulta);
    if ($r1 -> num_rows > 0){
   // echo "<table class='tabla'>";
    //echo "<th>Descripcion</th>";
        while($f1 = $r1 -> fetch_array()){
            echo "<div id='resultado_elemento'  >";			 
            echo "<table border='0'>";
            echo "<tr>";
            echo "<td style=' width:10px; text-align: left;' class='tipo_menu'>";
            echo	"Folio<br>".$f1['Folio'];
            echo " </td>";
            echo "<td width='90%' class='tipo_nitavu'>";								
            echo "<table border='0'>";
            echo "<tr>";							
            echo "<td>";
            echo "<span class='normal tmediano'>".$f1['Paterno']." ".$f1['Materno']." ".$f1['Nombre']."</span> ";
            echo "<span class='pc tchico'><br>Delegación: ".$f1['Delegacion']." Programa: ".$f1['Programa']."</span>";
            echo "<span class='pc tchico'><br>Descripción: ".$f1['EstatusCuenta']."   Estatus: ".$f1['Estatus']."</span>";
            if($f1['Cancelado']==1){
                echo "<span class='pc tchico' style='color:red;'><br>CANCELADA</span>";
            }
            echo "</td>";
            echo "<td style='text-align: right; width='10px;'>";
                echo "<a href='".$link."?Folio=".$f1['Folio']."&IdDelegacion=".$f1['IdDelegacion']."&IdPrograma=".$f1['IdPrograma']."'><img src='icon/entrar.png' class='icono' title='Ver Solicitud'></a>";
            echo "</td>";
            echo "</tr>";
            echo "</table>";
            echo "</td>";
            echo "</tr></table>";
            echo "</div>";
            
        }
        
    }else{
        echo "Sin resultados";
    }
    
}

function crearFolioTramite($FolioTramite,$IdPrograma, $IdDelegacion, $Folio, $nitavu){
    require("config.php");
    if($FolioTramite == ""){
        //SI NO HAY FOLIO HAY QUE CREAR UN NUEVO REGISTRO
        $FolioTramite = nsolicitud(TRUE);  
        $idTipoSolicitud = TipoSolicitud($IdPrograma);
        $IdDpto = nitavu_dpto($nitavu);
        $IdSolicitante = buscarIdSolicitante($IdPrograma, $IdDelegacion, $Folio);
        $CURP = curpBeneficiarioVivienda($IdSolicitante);
        $Nombre = nombreBeneficiarioVivienda($IdSolicitante);
        $sql = "INSERT INTO solicitudestemp(IdSolicitud, IdTipoSolicitud, Curp, NitavuCaptura,Fecha,Hora, DptoCaptura, Estado, NombreBeneficiario, FolioVivienda, IdPrograma, IdDelegacion) 
        VALUES ('".$FolioTramite."', '".$idTipoSolicitud."', '".$CURP."','".$nitavu."', '".$fecha."','".$hora."', '".$IdDpto."', 1, '".$Nombre."', ".$Folio.", ".$IdPrograma.", ".$IdDelegacion.")";
        if ($conexion->query($sql) == TRUE){
            historia($nitavu,"Cree un folio para evaluar una solicitud que inicio en vivienda: Guardo la solicitud con Folio " . $FolioTramite."");
            nsolicitud(FALSE); 
            return $FolioTramite;
        }else {
            historia($nitavu,"Error al crear un folio para evaluar una solicitud que inicio en vivienda: Guardo la solicitud con Folio " . $FolioTramite."");
          echo '<script> NPush("ERROR: No se pudo crear la solicitud para:'.$CURP.'-'.$Nombre.'", "PLataforma ITAVU")</script>';
        }
    }
}

