    if ($rc -> num_rows > 0){
            
        while($f = $rc -> fetch_array())
        { 
            //condiciones para ver cual corrida tomar
          /*  if($f['ANTERIOR'] == '1'){
                $sql = "SELECT * from creditos WHERE IdPrograma = ".$IdPrograma." and IdDelegacion = ".$IdDelegacion." ";
            }elseif($f['TODAS'] == '1'){
