            }else if($f['MUNICIPIOS'] == '1'){
                //buscar minicipio de donde se requiere 

            }
            */
            
            
            
            
            historia ($nitavu,"Cree la corrida financiera de la solicitud: ".$FolioTramite." con IdPrograma:".$IdPrograma.", IdDelegacion: ".$IdDelegacion.", Folio:".$FolioVivienda."");
            //CAT 15-rECURSO FONHAPO
            if (GuardarSolicitudDato($FolioTramite, 105, $f['RFonhapo'], "text", $nitavu, 15,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 105_15');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 106, $f['F_GtsAdmon'], "text", $nitavu, 15,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 106_15');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 107, $f['SubsidioFonhapo'], "text", $nitavu, 15,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 107_15');</script>"; }
        
            //CAT 16- RECURSOS DEL ITAVU
            if (GuardarSolicitudDato($FolioTramite, 105, $f['RFonhapo'], "text", $nitavu, 16,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 105_16');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 106, $f['F_GtsAdmon'], "text", $nitavu, 16,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 106_16');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 107, $f['SubsidioItavu'], "text", $nitavu, 16,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 107_16');</script>"; }
        
            //CAT 17-CREDITO
            if (GuardarSolicitudDato($FolioTramite, 109, $f['IdTipoMoneda'], "select", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 109_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 110, $f['MontoCredito'], "text", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 110_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 111, $f['IdPagoInicial'], "select", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 111_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 112, $f['MontoPagoInicial'], "text", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 112_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 113, $f['AplicaGtsAdmon'], "select", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 113_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 106, $f['GtsAdmon'], "text", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 106_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 114, $f['MontoEscrituracion'], "text", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 114_17');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 107, ($f['SubsidioFonhapo'] + $f['SubsidioItavu']), "text", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 107_17');</script>"; }
            if($f['IdTipoPago']== 4){
                $pago = 0;
            }else{
                //que es pago inicia
                $pago = $f['MontoPagoInicial'];
            }
            $totalaFinanciar =$f['MontoCredito'] + $f['MontoEscrituracion'] + $f['GtsAdmon'] - ($f['SubsidioFonhapo'] + $f['SubsidioItavu']) - $pago;
            if (GuardarSolicitudDato($FolioTramite, 115, $totalaFinanciar, "text", $nitavu, 17,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 107_17');</script>"; }
        
            //CAT 18-FORMA DE PAGO
            if (GuardarSolicitudDato($FolioTramite, 116, $f['IdTipoPago'], "select", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 116_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 117, $f['TotalPagos'], "text", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 117_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 118, $f['MontoPago'], "text", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 118_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 119, $f['MontoUltimoPago'], "text", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 119_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 106, $f['PGtsAdmon'], "select", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 106_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 120, $f['SegurodeVida'], "select", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 120_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 121, $f['OtroCargo'], "select", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 121_18');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 122, $f['IdConceptoCargo'], "select", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 122_18');</script>"; }
            $totalMontoPago = $f['MontoPago'] + ($f['MontoPago']* ($f['PGtsAdmon']/100)) + $f['SegurodeVida'] + $f['OtroCargo'];
            if (GuardarSolicitudDato($FolioTramite, 123, $totalMontoPago, "text", $nitavu, 18,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 113_16');</script>"; }
        
            //CAT 19- RECURSOS DEL BENEFICIARIO
            if (GuardarSolicitudDato($FolioTramite, 116, $f['RBeneficiario'], "text", $nitavu, 19,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 116_19');</script>"; }
        
            //CAT 20- TASA DE FINANCIAMIENTO
            if (GuardarSolicitudDato($FolioTramite, 124, $f['TasaAnualFin'], "text", $nitavu, 20,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 124_20');</script>"; }
        
            //CAT 21- INTERES DE MORATORIO
            if (GuardarSolicitudDato($FolioTramite, 125, $f['TipoIntMoratorio'], "select", $nitavu, 21,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 125_21');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 126, $f['TasaIntMora'], "text", $nitavu, 21,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 126_21');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 127, $f['MontoIntMora'], "text", $nitavu, 21,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 127_21');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 128, $f['DiasdeGracia'], "text", $nitavu, 21,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 128_21');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 129, $f['PeriodoMora'], "text", $nitavu, 21,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 129_21');</script>"; }
        
            //CAT 32- MINISTRACION DEL CREDITO
            if (GuardarSolicitudDato($FolioTramite, 130, $f['Ministracion1'], "text", $nitavu, 32,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 130_32');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 131, $f['Ministracion2'], "text", $nitavu, 32,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 131_32');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 132, $f['Ministracion3'], "text", $nitavu, 32,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 133_32');</script>"; }
            if (GuardarSolicitudDato($FolioTramite, 133, $f['ContratoMaestro'], "text", $nitavu, 32,2) == FALSE) {echo "<script>console.log('Error al guadar Folio: ".$FolioTramite.", IdRequisito: 133_32');</script>"; }
            }
        echo "<script>NPush('Se creo corrida financiera del crédito','Plataforma ITAVU');</script>";
    }else{
        echo "<script>NPush('No existe corrida financiera para este programa','Plataforma ITAVU');</script>";
        
    }


}

