function determinamontos($NumContrato,$programa){
    require("config.php");
    //verificar en la tabla de controlcontratos la info de la fecha del corte anterior
    //asi como la fecha del proximo corte y el estatus de la cuenta
    $sql = "Select * from controlcontratos where numcontrato = '".$NumContrato."'";
    $rc = $Vivienda -> query($sql);
    
    $r_count = $rc -> num_rows;
    if($r_count > 0){
        while($f = $rc -> fetch_array())
        {
            if($f['EstatusCuenta']==3){
                if($permisoEditarInteresMoratorioNomina == true){
                  /* Frame6.Enabled = True
                    Label5.Visible = True
                    Me.txtFolioRec.Visible = True
                    Me.txtFolioRec.Enabled = True
                    Me.CmdCorte2.Visible = True
                    txtFecha.Visible = True
                    Label41.Visible = True*/
                }else{
