                    Label41.Visible = False
                    Label5.Visible = False
                    Me.txtFolioRec.Enabled = False
                    Me.txtFolioRec.Visible = False
                    Me.CmdCorte2.Visible = False*/
                    mensaje('Esta cuenta esta marcada por descuento por nómina-Falta revisar lo del permiso','caja.php');
                }
            }else if($f['EstatusCuenta']==2){
                if($permisoAbonosParciales == true){
             
                    /*Me.txtFolioRec.Enabled = False
                    Me.txtFolioRec.Visible = False
                    Label5.Visible = False
                    Me.CmdCorte2.Visible = False
                    txtFecha.Visible = False
                    Label41.Visible = False*/
                }else{
                    mensaje("Usted no cuenta con permiso para realizar un cobro a cuentas regulares",'caja.php');
                    //Frame6.Enabled = False
                }
                //Me.txtFolioRec.Enabled = False
                //Me.CmdCorte2.Visible = False
            }

            if(isnull($f['FechaCorteAnterior'])){
                if(issnull($f['FechaProximoCorte'])){
                    mensaje("Ha ocurrido un error al tratar de buscar la FECHA DEL PROXIMO CORTE esta vacio, verifiquelo con el Administrador del Sistema","caja.php");
            
                }else{
                    $fechaCorteAnterior = DateAdd("m", -12, $f['FechaProximoCorte']);
                }
            }else{
                $fechaCorteAnterior = $f['FechaCorteAnterior'];
            }

            //lblfechainferior.Caption = DateAdd("d", 1, fecha_corte_ant)
            $fechaCorteSiguiente = $f['FechaProximoCorte'];
            //lblfechasuperior.Caption = fecha_corte_sig

            if($f['EstatusCuenta'] > 3 and $f['EstatusCuenta'] <> 9 and $programa <> 271){
                mensaje("La cuenta esta bloqueada no se puede recibir pago de momento","caja.php");
            }else{
                if ($f['EstatusCuenta'] = 3 and $permisoEditarInteresMoratorioNomina==true){
                    /*Me.lblFechaActual.Caption = "CUENTA DE NOMINA"
                    txtFecha.Visible = True
                    txtFecha.Enabled = True
