                    CmdCorte2.Visible = True*/
                    $Puede_continuar = True;
                }

                if($Puede_continuar == true){
                    if($f['EstatusCuenta']==1){
                        MsgBox_Lite("Esta cuenta YA ESTA SALDADA, no hay pagos pendientes por recibir.","caja.php");
                    }else{

                    }
                }
            }
        
        }
    }

}

function obtenerfactorconversion($clavemoneda, $fecha){
    require("config.php");
    $factorconversion = 0;
    if ($clavemoneda == 1){
        //si el tipo de moneda es pesos
        $factorconversion = 1;
    }else{
        //si el tipo de moneda esta en VSM
        $sql =  "SELECT FactorPeso FROM factorpeso WHERE (((IdTipoMoneda)=".$clavemoneda.") AND ((FechaInicia)<=".$fecha.") AND ((FechaTermina)>=".$fecha."))";
        //echo $sql;
        $rc= $conexion -> query($sql);
        $rows = $rc -> num_rows;
        if($rows>0){
            while($f = $rc -> fetch_array())
            {
                $factorconversion = $f['FactorPeso'];
            }   
        }else{
            $factorconversion = 1;
        }
    }
    return $factorconversion;
}


