function cambiarDiagonalesdeFecha($fecha){
    $fechaNueva = '';
    $fechaNueva = date('Y/m/d H:i:s', strtotime(str_replace('/', '-', $fecha)));
    $fechaNueva = date_format(date_create($fechaNueva), 'Y-m-d H:i:s');

    return $fechaNueva;
}

function liquidarConceptos($NumContrato,$nitavu){
    require("config.php");
    $sql = 'SELECT  historicopagos.TipoMov, descripcionmovimiento.DescripcionMovimiento, nummov 
    FROM  historicopagos 
    LEFT OUTER JOIN descripcionmovimiento ON historicopagos.TipoMov = descripcionmovimiento.idTipoMov
    where numcontrato= "'.$NumContrato.'" and not tipomov in (1,3,5,6,13,14,19,35,37,58,62,66,67,20,45,18,15,24,25,63,78,79,136)  AND historicopagos.Origen <> "CAN" and cancelado=0 order by historicopagos.TipoMov desc';
    echo $sql;
    $r = $Vivienda -> query($sql); 
  
    while($f1 = $r -> fetch_array()){
        $mov = $f1['nummov'];
        $localiza = 'Select * from historicopagos where numcontrato= '.$NumContrato.' and nummov='.$mov.'';
        echo $localiza;
        $r = $Vivienda -> query($localiza); 
    
        while($f2 = $r -> fetch_array()){
