function obtenerMaximoMovCuenta($NumContrato){
    require("config.php");
    $sql = 'select ifnull(MAX(NumMov),0) as maximo from historicopagos where Cancelado = 0 and NumContrato="'.$NumContrato.'"';
    //echo $sql;
    $r = $Vivienda -> query($sql); 
  
    while($f = $r -> fetch_array()){
       return $f['maximo'];
    }
}

