function sumasaldoCapitalCorriente($NumContrato, $maxMov){
    require("config.php");
    $sql = 'SELECT historicopagos.* from historicopagos WHERE  (NumContrato = "'.$NumContrato.'")  AND (NumMov = '.$maxMov.') and Cancelado = 0';
    
    //echo $sql;
    $r = $Vivienda -> query($sql); 

    $SaldoCapitalCorriente = '0';
    while($f = $r -> fetch_array()){
        $SaldoCapitalCorriente = $f['SaldoCapitalCorriente'] + $f['NuevoRezGts'] + $f['NuevoRezSeg'] + $f['NuevoRezOtrosGts'] + $f['NuevoRezMoratorios'] + $f['NuevoRezCapital'] + $f['NuevoRezFinanc'];
    }

    return $SaldoCapitalCorriente;
}

