function totalRegistrosdeInformacionCuenta($NumContrato){
    require("config.php");
    $sql = 'SELECT COUNT(Nombre) as TotalRegistros
      FROM  programa INNER JOIN historicopagos 
			INNER JOIN  contratos ON historicopagos.NumContrato = contratos.NumContrato 
			INNER JOIN  solicitudes ON contratos.IdDelegacion = solicitudes.IdDelegacion AND contratos.IdPrograma = solicitudes.IdPrograma AND  contratos.Folio = solicitudes.Folio 
			INNER JOIN solicitantes ON solicitudes.IdSolicitante =
      solicitantes.IdSolicitante ON  programa.IdPrograma = solicitudes.IdPrograma 
			LEFT OUTER JOIN catcolonia INNER JOIN  lotes ON catcolonia.IdMunicipio = lotes.IdMunicipio AND catcolonia.IdColonia = lotes.IdColonia ON  contratos.IdLote = lotes.IdLote
      Where 
      contratos.NumContrato = "'.$NumContrato.'" and
      historicopagos.TipoMov in (3,13,19,78,79,63) and historicopagos.origen<>"RST"
      and historicopagos.cancelado=0
      GROUP BY contratos.NumContrato, solicitantes.Nombre, solicitantes.Paterno, solicitantes.Materno,
      contratos.Folio,  contratos.IdPrograma, contratos.MontoCredito, contratos.IdDelegacion, contratos.IdLote,
      lotes.Manzana , lotes.Lote, catcolonia.Colonia, programa.IdTipoTramite
      HAVING (contratos.NumContrato = "'.$NumContrato.'")';
    
      $r = $Vivienda -> query($sql); 
  
    while($f = $r -> fetch_array()){
       return $f['TotalRegistros'];
    }
}

