function sumaMoratorios2018($NumContrato){
    require("config.php");
    //$sql = "Select sum(moratoriosperiodo) as sumamora from historicopagos where tipomov=5 and numcontrato='".$NumContrato."' And year(FechaOperacion) = 2018";
    $sql = " Select    SUM(nuevoRezmoratorios)as rezago, count(nummov)as movims From  historicopagos Where Cancelado = 0 And NumContrato='".$NumContrato."' And year(FechaOperacion) = 2018 And TipoMov not in (13) ";
    
    //echo $sql;
    $r = $Vivienda -> query($sql); 
  
    while($f = $r -> fetch_array()){

        if(is_null($f['rezago'])){
            $rezago = 0;
        }else{
            $rezago = $f['rezago'];
        } 
        if(is_null($f['movims'])){
            $movims = 0;
        }else{
            $movims = $f['movims'];
        } 

        if($rezago == 0 and $movims == 12){
            return 1;
        }else{
            return 0;
        }    
    }
}

