function SiguienteFecha($NumContrato,$fechaSuperior){
    require("config.php");
    $FechaEmision = fechaEmisionContrato($NumContrato);
    $fechaSuperior = FechaProximoCorteControlContratos($NumContrato);
    //echo 'fecha'.$FechaEmision;
    if($FechaEmision != ""){
        //si ya contrato
        if ($fechaSuperior !=  "" ){
            $EsPrimerPago = 'no';

            $SiguienteFecha = proximaFecha($fechaSuperior);
                
        }else{
             //si no ha contratado aun
            $EsPrimerPago = 'si';
            //buscamos IdFechaBase en contratos
            $IdFechaBase = IdFechaBaseContratos($NumContrato);
            $sql = "Select nombretabla, nombrecampo from fecharefprimpago where idfechabase = ".$IdFechaBase."";
            //echo $sql;
            $r = $Vivienda -> query($sql); 
    
            while($f = $r -> fetch_array()){
                $nombretabla = $f['nombretabla'];
                $nombrecampo = $f['nombrecampo'];
            }

            $sql2 = "Select ".$nombrecampo." from ".$nombretabla." where cancelado<>1 and numcontrato = '".$NumContrato."'";
            //echo $sql2;
            $r2 = $Vivienda -> query($sql2); 
    
            while($f2 = $r2 -> fetch_array()){
                $fechabase = $f2[$nombrecampo];
            }

            if($fechabase != ''){
                $SiguienteFecha = proximaFecha($fechabase);
            }else{
                $SiguienteFecha = 'FALSE';
            }
        }
               

    }else{
        //en contratacion esta vacio fecha emision 
        $SiguienteFecha = 'FALSE';
       
    }

    return $SiguienteFecha;
}

function varPeriodosXAño($NumContrato){
    //$varDiasdePago = obtenerDiasDePago($NumContrato);

    $periodo = IdTipoPagoContratos($NumContrato);   //MENSUAL
    $PeriodoMora = PeriodoMoraContratos($NumContrato);
    if($PeriodoMora == 30){
        $periodo = 3;
    } 
    switch ($periodo) {
        case 1:
            $varPeriodosXAño = 52;
            break;
        case 2:
            $varPeriodosXAño = 24;
            break;
        case 3:
            $varPeriodosXAño = 12;
            break;
        case 4:
            $varPeriodosXAño = 6;
            break;
        default:
            $varPeriodosXAño = 1;
            break;
    }
                
     return $varPeriodosXAño;

}

function getUltimoDiaMes($elAnio,$elMes) {
    return date("d",(mktime(0,0,0,$elMes+1,1,$elAnio)-1));
}


function proximaFecha($fechaSuperior){
    //fecha introducida por el usuario
    $fecha = date_create($fechaSuperior);
    $fechanueva = date_format($fecha,"Y-m-d");
    $fechanueva = explode("-", $fechanueva);
    $fechaReg='';
    //preguntamos si es el ultimio día del mes, entramos aqui por que hay que crear la fecha siguiente de 0
    if(getUltimoDiaMes($fechanueva[0],$fechanueva[1]) == $fechanueva[2]){
        //OBTENEMOS EL MES
        $mes = $fechanueva[1];
        //y le sumamos uno
        if($mes == 12){
            $mesnew = 1;
        }else{
            $mesnew = $mes + 1;
        }
        //Si el mes es 1 entonces debemos sumar un año
        if($mesnew == 1){
           $anio = $fechanueva[0]+1;
        }else{
            $anio = $fechanueva[0];
        }
        //obtengo el dia ultimo del mes nuevo 
        $ultimoDia = getUltimoDiaMes($fechanueva[0],$mesnew);
        if($mesnew >= 10){
            //creo la nueva fecha
            $fechaReg = $ultimoDia.'-'.$mesnew.'-'.$anio;
        }else{
            $fechaReg = $ultimoDia.'-0'.$mesnew.'-'.$anio;

        }

        $SiguienteFecha = $fechaReg;
    }else{//si es cualquier otro dia no hay problema y podemos utilizar las funciones de php
        $dt = new DateTime($fechaSuperior);
        $dt->modify( 'next month' );
        $SiguienteFecha = $dt->format( 'd-m-Y' );
    }
   
    return $SiguienteFecha; 
}

function proximaFecha2meses($fechaSuperior){
    //fecha introducida por el usuario
    $fecha = date_create($fechaSuperior);
    $fechanueva = date_format($fecha,"Y-m-d");
    $fechanueva = explode("-", $fechanueva);
    $fechaReg='';
    //preguntamos si es el ultimio día del mes, entramos aqui por que hay que crear la fecha siguiente de 0
    if(getUltimoDiaMes($fechanueva[0],$fechanueva[1]) == $fechanueva[2]){
        //OBTENEMOS EL MES
        $mes = $fechanueva[1];
        //y le sumamos dos
        if($mes == 12){
            $mesnew = 2;
        }else if($mes == 11){
            $mesnew = 1;
        }else{
            $mesnew = $mes + 2;
        }
        //Si el mes es 1 entonces debemos sumar un año
        if($mesnew == 1){
           $anio = $fechanueva[0]+1;
        }else{
            $anio = $fechanueva[0];
        }
        //obtengo el dia ultimo del mes nuevo 
        $ultimoDia = getUltimoDiaMes($fechanueva[0],$mesnew);
        if($mesnew >= 10){
            //creo la nueva fecha
            $fechaReg = $ultimoDia.'-'.$mesnew.'-'.$anio;
        }else{
            $fechaReg = $ultimoDia.'-0'.$mesnew.'-'.$anio;

        }

        $SiguienteFecha = $fechaReg;
    }else{//si es cualquier otro dia no hay problema y podemos utilizar las funciones de php
        $dt = new DateTime($fechaSuperior);
        $dt->modify( '+2 month' );
        $SiguienteFecha = $dt->format( 'd-m-Y' );
    }
   
    return $SiguienteFecha; 
}
  
