function ObtenerPrimerDiaMes(){
    $month_start = strtotime('first day of this month', time());
    $Primer = date('d/m/Y', $month_start);
    return $Primer;
  
}
function ObtenerUltimoDiaMes(){
    $month_end = strtotime('last day of this month', time());
    $Ultimo = date('d/m/Y', $month_end);
    return $Ultimo;
}

function ObtenerPrimerDiaMesconFecha(){
    $month_start = strtotime('first day of this month', time());
    $Primer = date('d/m/Y', $month_start);
    return $Primer;
  
}
function ObtenerUltimoDiaMesconFecha($fecha){
    
   
    $Ultimo = date("Y-m-t", strtotime($fecha));
    return $Ultimo;
}



