function number_words($valor,$desc_moneda, $sep, $desc_decimal){
    $arr = explode(".", $valor);
    $entero = $arr[0];
    if (isset($arr[1])) {
        $decimos = strlen($arr[1]) == 1 ? $arr[1] . '0' : $arr[1];
    }
    
    $fmt = new \NumberFormatter('es', \NumberFormatter::SPELLOUT);
    if (is_array($arr)) {
        $num_word = ($arr[0]>=1000000) ? "{$fmt->format($entero)} de $desc_moneda" : "{$fmt->format($entero)} $desc_moneda";
        if (isset($decimos) && $decimos > 0) {
            $num_word .= " $sep {$fmt->format($decimos)} $desc_decimal";
        }
    }
    return $num_word;
}

function ConvierteVSM($Monto, $Fecha, $TipoRequerido, $TipoProporcionado){
    require("config.php");
    //se busca el factor de conversion valido en esa fecha en funcion de TipoRequerido
    $sql  = "SELECT FactorPeso FROM factorpeso WHERE IdTipoMoneda=".$TipoRequerido." AND (FechaInicia<='".$Fecha."') AND (FechaTermina>='".$Fecha."')"; 
    //echo $sql;
    $r = $Vivienda -> query($sql); 
    $r_count = $r -> num_rows;
    if($r_count>0){
        while($f = $r -> fetch_array()){
            $factor = $f['FactorPeso'];
        }  
        if ($TipoProporcionado == 1 ){
            //se divide el monto actual en pesos entre el factor para convertir a VSM
            return  ($Monto / $factor);
        }else{
            //se multiplica el monto actual en VSM por el factor para convertir a Pesos
            return  ($Monto * $factor);
        }
    }else{
        return 'SIN DATO';
    }
}

function Delegado($IdDelegacion){
    require("config.php");
    $sql = "select empleados.nombre as Delegado
    from cat_delegaciones, cat_gerarquia, empleados
    where cat_delegaciones.id = ".$IdDelegacion."
    AND cat_gerarquia.nivel = 'Del'
    AND cat_gerarquia.nombre LIKE CONCAT('%', cat_delegaciones.nombre, '%')
    and empleados.nitavu = cat_gerarquia.titular";
    $r = $conexion -> query($sql); 
    //echo $sql;
    $r_count = $r -> num_rows;
    if($r_count>0){
        while($f = $r -> fetch_array()){
            return $f['Delegado'];
        }
    }else {
        return '';
    }

}

function Obtiene_MpioDelTerreno($idlote){
    require("config.php");
    //Corrige el municipio de ciertas colonias ya que fisicamente pertenece a otro municipio
    if ($idlote == 0 ){
        return "";
    }

    $sql = " SELECT lotes.IdMunicipio, lotes.IdColonia, municipios.Municipio
    FROM lotes 
    LEFT OUTER JOIN  municipios ON lotes.IdMunicipio = municipios.IdMunicipio
    Where lotes.IdLote = '".$idlote."'";
    $r = $Vivienda -> query($sql); 
  
    while($f = $r -> fetch_array()){
        //Ciudad Madero, Fracc. Unidos Avanzamos  -- > Pertenece fisicamente a Altamira
        if ( $f["IdMunicipio"] == 9 and $f["IdColonia"] == 79 ){
            return "ALTAMIRA";
        }else{
            // Tampico, Fracc. Unidos Avanzamos  -- > Pertenece fisicamente a Altamira
            if ($f["IdMunicipio"] == 38 and $f["IdColonia"] == 63){
                return "ALTAMIRA";
            }else{
                return $f["Municipio"];
            }
        }
    }
}

function diasDePago($IdPrograma){
    require("config.php");
    $sql = "SELECT DiasdePago FROM programa WHERE IdPrograma = '".$IdPrograma."'";
    $r = $Vivienda -> query($sql); 
  
    while($f = $r -> fetch_array()){
        return $f['DiasdePago'];
    }
}



