function guardarVale($NumContrato, $IdDelegacion, $IdPrograma, $Folio, $FechaEntrega, $Bloquera, $ImporteVale, $CasaComercial, $Beneficio, $nitavu){
    require("config.php");
    $numvale = '';
    $sumamontos = 0;
    if($ImporteVale <> 0){
        //verificar suma de montos + val (txtvale1importe) <= txtbeneficio
        $sql = 'SELECT SUM(Monto) AS SumadeMonto From ministracioncredito Where Cancelado=0 AND NumContrato="'.$NumContrato.'"';
        
        //echo $sql.'<br>';
        $r = $Vivienda -> query($sql); 
        while($f = $r -> fetch_array()){
            if(is_null($f['SumadeMonto'])){
                $sumamontos = 0;
            }else{
                $sumamontos = $f['SumadeMonto'];
            }
            if($sumamontos + $ImporteVale <= $Beneficio){
                //obtener numvale
            
                $numvale = SigNumMinistracion($NumContrato);
                $NombreCasa = casasComerciales($CasaComercial);
                //verificar que la casa comercial seleccionada no se encuentra en la lista de vales existentes
                //como busco la casa comercial 
                //BUSCAMOS EN BD SI EXISTE UN REGISTRO DE UNA CASA COMERCIAL CON ESE NUMERO DE CONTRATO
                $sql = "SELECT IdCasacomercial FROM ministracioncredito WHERE NumContrato=".$NumContrato." and IdCasaComercial=".$CasaComercial." AND Cancelado = 0";
                //echo $sql.'<br>';
                $r = $Vivienda -> query($sql); 
                $r_count2 = $r -> num_rows;
                if($r_count2>0){
                                     
                    //error La casa comercial elegida ya existe en la lista de vales
                    mensaje("Esa casa comercial ya esta en la lista. Seleccione otra casa comercial o elimine el registro de esta para modificar el monto asignado al vale",  "vales.php?delegaciones=".$IdDelegacion."&programa=".$IdPrograma."&_folio=".$Folio."");
                        
                    
                }else{
                    $sqlMinistracion="INSERT INTO ministracioncredito  (NumContrato,NumMinistracion ,Cancelado ,Enviar,FechaCaptura  ,
                    FechaEmision ,FechaEntrega ,FechaEnvio  , FechaUltimaMod  ,Folio ,IdCasaComercial ,IdDelegacion ,IdEmpCrea  ,
                    IdEmpModifica,IdPrograma ,IdTipoMinistracion,Monto ,CasaComercial ,FechaImpProv,FechaSolicImp ,
                    FechaImpDupli,Observaciones ,idbloquera,LLegoValeFisico,Oficio,FechaOficio ,OrigenDeEnvio)
                    VALUES ('".$NumContrato."','".$numvale."',0,1,NOW(),'".$FechaEntrega."',NOW(),'','',".$Folio.",".$CasaComercial.",".$IdDelegacion.",".$nitavu.",'',".$IdPrograma.",'',
                    ".$ImporteVale.",'".$NombreCasa."','','','','',".$Bloquera.",'','','',".$IdDelegacion.")";
                    //echo $sqlMinistracion.'<br>';
                    if ($Vivienda->query($sqlMinistracion) == TRUE){                                   
                        
                        echo "<script>
                            NPush('Se guardo con éxito el vale.','Plataforma ITAVU')
                        </script>";                                        
                    }else{ 
                        return mensaje('ERROR; Hubo un error al momento de guardar el vale, favor de intentarlo de nuevo.', "vales.php?delegaciones=".$IdDelegacion."&programa=".$IdPrograma."&_folio=".$Folio."");                                       
                        
                    }
                }
                
               
               
            }else{
                //error Monto maximo = txtbeneficio - suma de montos
                mensaje("El monto maximo admitido es ".($Beneficio - $sumamontos)."","vales.php?delegaciones=".$IdDelegacion."&programa=".$IdPrograma."&_folio=".$Folio."");
                $ImporteVale = 0;
                
            }
        }
    }else{
        mensaje("El monto no puede estar vacio!", "vales.php?delegaciones=".$IdDelegacion."&programa=".$IdPrograma."&_folio=".$Folio."");
    }


    //selecionamos la ministracion 
    $sql1 = "SELECT * FROM ministracioncredito WHERE NumContrato='".$NumContrato."' AND NumMinistracion=".$numvale." ";
    //echo $sql1;
    $r1 = $Vivienda -> query($sql1); 
    while($f1 = $r1 -> fetch_array()){
        $NumContrato = $f1['NumContrato'];
        $NumMinistracion = $f1['NumMinistracion'];
        $IdCasaComercial = $f1['IdCasaComercial'];
        $CasaComercial = $f1['CasaComercial'];
        $Monto = $f1['Monto'];

        if($f1['FechaEmision'] == ""){
            $sql2 = "UPDATE ministracioncredito SET FechaEmision = '".$FechaEntrega."' WHERE NumContrato='".$NumContrato."' AND NumMinistracion=".$NumMinistracion."  ";
            //echo $sql2;
            if ($Vivienda->query($sql2) == TRUE) {
                echo "TRUE";
            }else{
                echo "FALSE";
            }
        }

        if($IdPrograma == 205 or $IdPrograma == 206 or $IdPrograma == 227 or $IdPrograma == 228 or  $IdPrograma == 179 or $IdPrograma == 182 or $IdPrograma == 220){
            $sql2 = "UPDATE ministracioncredito SET idbloquera=".$Bloquera." where NumContrato=='".$NumContrato."' and NumMinistracion=".$NumMinistracion."";
            //echo $sql2;
            if ($Vivienda->query($sql2) == TRUE) {
                echo "TRUE";
            }else{
                echo "FALSE";
            }
        }

        $FechaMin1 = FechaMin1Contrato($NumContrato);
        $FechaMin2 = FechaMin2Contrato($NumContrato);
