function revisa($IdDelegacion, $IdPrograma, $IdBloquera){
//(deleg As Integer, prog As Integer, bloq As Integer)
    require("config.php");
    $sql = "select * from metasbloquera where iddelegacion=".$IdDelegacion." and IdPrograma=".$IdPrograma." and idbloquera=".$IdBloquera."";
    $r = $Vivienda -> query($sql); 
    while($f = $r -> fetch_array()){
        if(is_null($f['TechoFinanciero'])){
            $TechoFinanciero = 0;
        }else{
            $TechoFinanciero = $f['TechoFinanciero'];
        }
    }

    
    $sql = "Select sum(monto) as montoejercido from ministracioncredito where cancelado=0 and iddelegacion=".$IdDelegacion." and Idprograma=".$IdPrograma."and idbloquera=".$IdBloquera."";
    $r = $Vivienda -> query($sql); 
    while($f = $r -> fetch_array()){
        if(is_null($f['montoejercido'])){
            $TotalValImpresos = 0;
        }else{
            $TotalValImpresos = $f['montoejercido'];
        }
    }


    if(($TotalValImpresos + $Beneficio) > $TechoBloquera){
        return False;
    }else{
        return True;
    }

}

function obtener_digito($Valor){
    
    $referencia = Trim($Valor);
    $largostr = strlen($referencia);
    $multiplo = 1;
    $N = 1;
    $suma =0;
    for($i=0; $i< $largostr ; $i++){
        $multiplo = $multiplo + $N;
        $N = $N * (-1);
        $sumando = substr($referencia, $i, 1) * $multiplo;
        if($sumando > 9){ 
            $sumando = (int)substr($sumando, 1, 1) + (int)substr($sumando, 2, 1);
        }
        $suma = $suma + $sumando;
    }
    $residuo = $suma % 10;
    if($residuo == 0){
        $digitover =  0;
    }else{
        $digitover = 10 - $residuo;
    } 
    $obtener_digito = round($digitover);
}

function SigNumMinistracion($NumContrato){
    require("config.php");
    $sql = "SELECT MAX(NumMinistracion) AS MaxNum FROM ministracioncredito WHERE NumContrato=".$NumContrato." GROUP BY NumContrato";
    //echo $sql;
    $r = $Vivienda -> query($sql); 
    $vale = '';
    while($f = $r -> fetch_array()){
        if(is_null($f['MaxNum'])){
            $vale = 1;
        }else{
            $vale = $f['MaxNum'] + 1;
        }
    }

    return $vale;
}


