function Valida_TechoFinanciero($IdDelegacion, $IdPrograma){
    require("config.php");
    $NA_TechoFinAut = 0;
    $NA_TechoFin = 0;
    $M_TechoFinAut = 0;
    $M_TechoFin = 0;
    $RecursoActual = 0;
    $sql = "SELECT * FROM metas WHERE IdDelegacion=".$IdDelegacion." and IdPrograma=".$IdPrograma."";
    //echo $sql;
    $r = $Vivienda -> query($sql); 
    $r_count = $r -> num_rows;
    if($r_count>0){
        while($f = $r -> fetch_array()){
            $NA_TechoFinAut = is_null($f['AccionesAutorizadas'])  ? 0 : $f['AccionesAutorizadas']; 
            $M_TechoFinAut = is_null($f['MontoAutorizado']) ? 0 : $f['MontoAutorizado']; 
            $NA_TechoFin = is_null($f['TotalAcciones'])  ? 0 : $f['TotalAcciones']; 
            $M_TechoFin = is_null($f['TechoFin']) ? 0 : $f['TechoFin']; 

            if($M_TechoFin > $M_TechoFinAut){
                $RecursoActual = ($M_TechoFin) - ($M_TechoFinAut);
                //hay recursos
                echo "<script>
                    NPush('Cuentas con un techo financiero de: $'".number_format($RecursoActual,2,'.',',')."','Plataforma ITAVU')
                </script>";
                //echo modalSinRedirigir("Cuentas con un techo financiero de: $".number_format($RecursoActual,2,'.',','));
            }elseif ($M_TechoFin == $M_TechoFinAut){
                $RecursoActual = ($M_TechoFin) - ($M_TechoFinAut);
                //se llego a la meta
                echo "<script>
                    NPush('Monto del Techo financiero del programa es cero ó no hay mas recursos a asignar, por que se ha concluido la meta','Plataforma ITAVU')
                </script>";
                //echo modalSinRedirigir("Monto del Techo financiero del programa es cero ó no hay mas recursos a asignar, por que se ha concluido la meta");
            }else{
                //se exedio la meta
                $RecursoActual = ($M_TechoFinAut) - ($M_TechoFin);
                echo "<script>
                    NPush('Se ha exedido el techo financiero autorizado con una cantidad de: $".number_format($RecursoActual,2,'.',',')."','Plataforma ITAVU')
                </script>";
                //echo modalSinRedirigir("Se ha exedido el techo financiero autorizado con una cantidad de: $".number_format($RecursoActual,2,'.',','));
            }
            return $RecursoActual;
        }
    }else{
        echo "<script>
            NPush('No se  ha configurado las metas para este programa','Plataforma ITAVU')
        </script>";
        //echo modalSinRedirigir("No se  ha configurado las metas para este programa");
        
    }
}

