     $Num = $vNumMov + 1 ;
     
    if ($IdPrograma == 251 or $IdPrograma  == 254 or $IdPrograma == 255 or $IdPrograma == 256 or $IdPrograma == 257 or $IdPrograma == 258 or $IdPrograma == 259 or $IdPrograma == 260 or $IdPrograma == 261 or $IdPrograma == 262 or $IdPrograma == 263 or $IdPrograma == 264 or $IdPrograma == 265 or $IdPrograma == 266 or $IdPrograma == 267 or $IdPrograma == 268 or $IdPrograma == 269 or $IdPrograma == 271 or $IdPrograma == 273 or $IdPrograma == 274 or $IdPrograma == 275 or $IdPrograma == 280){
        $SaldoCapitalCorriente = $SaldoCapitalCorriente;
        if ($saldoexento < $importe){
          return mensaje("El SALDO EXENTO de esta cuenta es menor al Subsidio que esta tratando de registrar. Verifique la cantidad y vuelva a intentar, Favor de verificar", $link);
        }else{
            $saldoexento = $saldoexento - $importe;       
         }
    }else{
        echo 'Saldo capital corriente '.$SaldoCapitalCorriente;
        echo 'Importe '.$importe;
        echo 'Saldo Exento '.$SaldoExento;
        if ($SaldoCapitalCorriente >= $importe){
      
            $SaldoCapitalCorriente = $SaldoCapitalCorriente - $importe;
        }else{
            if( $SaldoCapitalCorriente + $NuevoRezCapital >= $importe){
                $SaldoCapitalCorriente = 0;
                $RezCapitalCubierto = $importe - $SaldoCapitalCorriente;
                $NuevoRezCapital = $NuevoRezCapital - ($importe - $SaldoCapitalCorriente);
            }else{
                if(($SaldoCapitalCorriente + $NuevoRezCapital + $NuevoRezFinanc) >= $importe){
                    $SaldoCapitalCorriente = 0;
                    $NuevoRezCapital = 0;
                    $NuevoRezFinanc = ($NuevoRezFinanc - ($importe - $NuevoRezCapital - $SaldoCapitalCorriente));
                }else{
                    if(($SaldoCapitalCorriente + $NuevoRezCapital + $NuevoRezFinanc + $NuevoRezMoratorios) >= $importe){
                        $SaldoCapitalCorriente = 0;
                        $NuevoRezCapital = 0;
                        $NuevoRezFinanc = 0;
                        $NuevoRezMoratorios = ($NuevoRezMoratorios - ($importe - $NuevoRezFinanc - $NuevoRezCapital - $SaldoCapitalCorriente));
                    
                    }else{
                        if($SaldoExento >= $importe){
                            $SaldoExento = $SaldoExento - $importe;
                            $SaldoCapitalCorriente = $SaldoCapitalCorriente;
                        }else{
                           return mensaje("No hay suficiente deuda para aplicar el Subsidio, requiere un análisis más profundo", $link);
                        }
                    }
                }
            }
        }
    }

    if($ref == ''){
