    VALUES ('".$NumContrato."','".$Num."','".$importe."',now(),'".$FechaCorte."','','','".$NuevoRezGts."',0,0,'','".$NuevoRezGts."','".$NuevoRezSeg."',0,0,0,'".$NuevoRezSeg."', '".$NuevoRezOtrosGts."',
