    0, '".$SaldoCapitalCorriente."', 'CNE', '".$cargo."', '".$observaciones."', 1, '".$nitavu."', '', now(), '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '".$IdDelegacion."')";
    echo $nuevo;
    if ($Vivienda->query($nuevo) == TRUE){  
