function obtener_nuevo_id($numescritura){
    require("config.php");

    $iddel = substr($numescritura,0,2);

    $sql = "select if(isnull(max(consecutivo)),0,max(consecutivo)) + 1 as cons from seguimiento where  iddelegacion = ".$iddel."";
    echo $sql;

    $r = $Vivienda -> query($sql);
    while($f = $r -> fetch_array()) {
        return $f['cons'];
    }

}

