function DireccionRealizoUltimoComentario($IdActividad){
    require("config.php");
   // $direccion=quienEsmiDireccion(nitavu_dpto($nitavu));   
    $sql = "SELECT * FROM historial_actividades where IdActividad = ".$IdActividad." ORDER BY id DESC";
    $nitavu=ObtenerNitavuDirector();
    
    $rc= $conexion -> query($sql);
  
    if($f = $rc -> fetch_array()){
        $nivel =aplicacion_nivel('ap130', $f['nitavu']);
        if(($nitavu==$f['nitavu'] or $nivel==2 ) and $f['visto']==0)
        {
            return 'TRUE';
        }else
        {
            return 'FALSE';
        }
        //return $f['Comentario'];
    }else{ 
        return 'FALSE';
    }
}

